/**
 * MMS PM Management Tables
 *
 * Preventive maintenance scheduling: PM types, material requirements, and schedules.
 * Core tables for the maintenance planning workflow.
 *
 * PM Hierarchy: Higher-level PMs satisfy lower-level requirements
 * - C4 satisfies C1, C2, C3 (resets their counters)
 * - Overhaul satisfies all PM types
 *
 * @see specs/003-database-schema.md Sections 3.5
 */

import { relations, sql } from 'drizzle-orm';
import {
  boolean,
  date,
  decimal,
  index,
  integer,
  pgTable,
  text,
  timestamp,
  uniqueIndex,
  uuid,
  varchar,
} from 'drizzle-orm/pg-core';
import { depots, fleets, tracks, trains } from './core-fleet';
import { materialCriticalityEnum, pmStatusEnum, shiftTypeEnum, trackTypeEnum } from './enums';
import { users } from './users';

/**
 * PM Types - Maintenance task definitions
 *
 * Defines the maintenance tasks for each fleet with their intervals
 * and resource requirements.
 *
 * Key concepts:
 * - interval_km / interval_months: Whichever triggers first
 * - satisfies_codes: PM hierarchy (C4 satisfies C1/C2/C3)
 * - early/late tolerance: Compliance window (default ±10%)
 *
 * Version management: PM intervals can change over the 12-year contract.
 * The effective_from/effective_to fields support versioning.
 */
export const pmTypes = pgTable(
  'pm_types',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    fleetId: uuid('fleet_id')
      .notNull()
      .references(() => fleets.id),
    pmCode: varchar('pm_code', { length: 20 }).notNull(), // 'C1', 'C2', 'C3', 'C4', 'OVERHAUL'
    pmName: varchar('pm_name', { length: 100 }).notNull(),
    version: integer('version').default(1),

    // Interval thresholds (whichever comes first)
    intervalKm: integer('interval_km'),
    intervalMonths: integer('interval_months'),

    // PM Hierarchy: which lower-level PMs does this PM satisfy?
    // When a C4 is completed, it satisfies C1/C2/C3 requirements
    // Example: C4 row has satisfies_codes = ['C1', 'C2', 'C3']
    satisfiesCodes: text('satisfies_codes').array(),

    // Resource requirements
    estimatedHours: decimal('estimated_hours', { precision: 6, scale: 2 }).notNull(),
    trackType: trackTypeEnum('track_type').notNull(),
    minTrackDays: integer('min_track_days').default(1), // How many days track is occupied

    // Compliance window tolerance (percentage)
    earlyTolerancePct: decimal('early_tolerance_pct', { precision: 5, scale: 2 }).default('10.0'),
    lateTolerancePct: decimal('late_tolerance_pct', { precision: 5, scale: 2 }).default('10.0'),

    // Certification requirements
    requiredCertifications: text('required_certifications').array(),

    // v2.1: PM type versioning for interval changes over contract life
    effectiveFrom: date('effective_from').notNull().default(sql`CURRENT_DATE`),
    effectiveTo: date('effective_to'), // NULL = current version
    supersededBy: uuid('superseded_by'), // Link to newer version

    // Canvas display properties
    displayColor: varchar('display_color', { length: 7 }),
    displayPriority: integer('display_priority').default(50),

    active: boolean('active').default(true),
    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    uniqueIndex('idx_pm_types_unique').on(table.fleetId, table.pmCode, table.version),
    index('idx_pm_types_current').on(table.fleetId, table.pmCode, table.effectiveFrom),
  ]
);

/**
 * PM Material Requirements - Bill of Materials
 *
 * Links PM types to required parts with quantities and criticality.
 *
 * Criticality levels determine scheduling constraints:
 * - BLOCKING: Cannot start PM without part (14-day hard constraint)
 * - DEFERRABLE: Can start, must have within X days
 * - CONSUMABLE: Nice-to-have, can substitute
 */
export const pmMaterialRequirements = pgTable(
  'pm_material_requirements',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    pmTypeId: uuid('pm_type_id')
      .notNull()
      .references(() => pmTypes.id),
    partNumber: varchar('part_number', { length: 50 }).notNull(),
    partDescription: text('part_description'),

    quantityPerPm: integer('quantity_per_pm').notNull().default(1),
    criticality: materialCriticalityEnum('criticality').notNull().default('BLOCKING'),

    leadTimeDays: integer('lead_time_days').default(14),
    substituteParts: text('substitute_parts').array(), // Alternative part numbers

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    uniqueIndex('idx_pm_materials_unique').on(table.pmTypeId, table.partNumber),
    index('idx_pm_materials_type').on(table.pmTypeId),
  ]
);

/**
 * PM Schedule - Planned and executed maintenance
 *
 * The core scheduling table. Each row represents a planned or completed PM.
 *
 * Key fields:
 * - constraint_start/end: Compliance window (calculated from PM type tolerances)
 * - is_locked: When true, optimizer cannot move this PM
 * - maximo_wo_id: Link to Maximo work order (when INPRG, PM is locked)
 * - scenario_id: NULL for production, non-NULL for what-if scenarios
 *
 * Status transitions:
 * SCHEDULED -> IN_PROGRESS -> COMPLETED
 * SCHEDULED -> DEFERRED -> SCHEDULED (new date)
 * SCHEDULED -> CANCELLED
 */
export const pmSchedule = pgTable(
  'pm_schedule',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    trainId: uuid('train_id')
      .notNull()
      .references(() => trains.id),
    pmTypeId: uuid('pm_type_id')
      .notNull()
      .references(() => pmTypes.id),

    // Scheduling
    targetDate: date('target_date').notNull(),
    targetMileageKm: integer('target_mileage_km'),
    status: pmStatusEnum('status').default('SCHEDULED'),

    // Compliance window
    constraintStart: date('constraint_start').notNull(), // Earliest allowed date
    constraintEnd: date('constraint_end').notNull(), // Latest allowed date

    // Resource assignment
    assignedDepotId: uuid('assigned_depot_id').references(() => depots.id),
    assignedTrackId: uuid('assigned_track_id').references(() => tracks.id),
    assignedHours: decimal('assigned_hours', { precision: 6, scale: 2 }),
    assignedShift: shiftTypeEnum('assigned_shift'),

    // Execution
    actualStartDate: date('actual_start_date'),
    actualEndDate: date('actual_end_date'),
    actualHours: decimal('actual_hours', { precision: 6, scale: 2 }),
    completedAt: timestamp('completed_at', { withTimezone: true }),
    completedMileageKm: integer('completed_mileage_km'),

    // Work order integration (Maximo)
    maximoWoId: varchar('maximo_wo_id', { length: 50 }),

    // Locking - prevents optimizer from moving
    isLocked: boolean('is_locked').default(false),
    lockedReason: varchar('locked_reason', { length: 100 }),
    lockedBy: uuid('locked_by').references(() => users.id),
    lockedAt: timestamp('locked_at', { withTimezone: true }),

    // Scenario support (NULL = production schedule)
    scenarioId: uuid('scenario_id'),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
    createdBy: uuid('created_by').references(() => users.id),
  },
  (table) => [
    index('idx_pm_schedule_train').on(table.trainId, table.targetDate),
    index('idx_pm_schedule_date').on(table.targetDate, table.status),
    index('idx_pm_schedule_depot').on(table.assignedDepotId, table.targetDate),
    index('idx_pm_schedule_scenario').on(table.scenarioId),
    index('idx_pm_schedule_canvas').on(table.targetDate, table.trainId),
    index('idx_pm_schedule_maximo').on(table.maximoWoId),
  ]
);

// ============================================================================
// Relations
// ============================================================================

export const pmTypesRelations = relations(pmTypes, ({ one, many }) => ({
  fleet: one(fleets, {
    fields: [pmTypes.fleetId],
    references: [fleets.id],
  }),
  materialRequirements: many(pmMaterialRequirements),
  schedules: many(pmSchedule),
}));

export const pmMaterialRequirementsRelations = relations(pmMaterialRequirements, ({ one }) => ({
  pmType: one(pmTypes, {
    fields: [pmMaterialRequirements.pmTypeId],
    references: [pmTypes.id],
  }),
}));

export const pmScheduleRelations = relations(pmSchedule, ({ one }) => ({
  train: one(trains, {
    fields: [pmSchedule.trainId],
    references: [trains.id],
  }),
  pmType: one(pmTypes, {
    fields: [pmSchedule.pmTypeId],
    references: [pmTypes.id],
  }),
  assignedDepot: one(depots, {
    fields: [pmSchedule.assignedDepotId],
    references: [depots.id],
  }),
  assignedTrack: one(tracks, {
    fields: [pmSchedule.assignedTrackId],
    references: [tracks.id],
  }),
  lockedByUser: one(users, {
    fields: [pmSchedule.lockedBy],
    references: [users.id],
    relationName: 'lockedBy',
  }),
  createdByUser: one(users, {
    fields: [pmSchedule.createdBy],
    references: [users.id],
    relationName: 'createdBy',
  }),
}));

/**
 * MMS Core Fleet Domain Tables
 *
 * Asset master data: depots, fleets, trains, routes, and tracks.
 * These form the foundation of the fleet management system.
 *
 * @see specs/003-database-schema.md Section 3.2
 */

import { relations } from 'drizzle-orm';
import {
  boolean,
  date,
  decimal,
  index,
  integer,
  pgTable,
  text,
  timestamp,
  uniqueIndex,
  uuid,
  varchar,
} from 'drizzle-orm/pg-core';
import { fitnessStatusEnum, trackTypeEnum } from './enums';

/**
 * Depots - Maintenance facilities
 *
 * Physical locations where trains are maintained and stored.
 * Each depot has a timezone for correct scheduling calculations.
 */
export const depots = pgTable(
  'depots',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    code: varchar('code', { length: 10 }).notNull().unique(),
    name: varchar('name', { length: 100 }).notNull(),
    location: varchar('location', { length: 200 }),
    timezone: varchar('timezone', { length: 50 }).default('Asia/Singapore'),
    active: boolean('active').default(true),
    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [uniqueIndex('idx_depots_code').on(table.code)]
);

/**
 * Fleets - Train types/manufacturers
 *
 * A fleet represents a group of similar trains from the same manufacturer.
 * PM types are defined per fleet as maintenance requirements vary by train model.
 */
export const fleets = pgTable(
  'fleets',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    code: varchar('code', { length: 10 }).notNull().unique(),
    name: varchar('name', { length: 100 }).notNull(),
    manufacturer: varchar('manufacturer', { length: 100 }).notNull(),
    model: varchar('model', { length: 100 }),
    baseDepotId: uuid('base_depot_id').references(() => depots.id),
    carsPerTrain: integer('cars_per_train').default(6),
    active: boolean('active').default(true),
    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [uniqueIndex('idx_fleets_code').on(table.code)]
);

/**
 * Trains - Individual train assets
 *
 * Core asset in the system. Each train belongs to a fleet and accumulates mileage.
 * The fitness_status determines if the train can be scheduled for operations or maintenance.
 *
 * Key fields:
 * - current_mileage_km: Cumulative km reading
 * - target_mileage_km: Calculated target for fleet mileage balancing
 * - mileage_variance_km: Deviation from target (positive = above target)
 */
export const trains = pgTable(
  'trains',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    fleetId: uuid('fleet_id')
      .notNull()
      .references(() => fleets.id),
    trainNumber: varchar('train_number', { length: 20 }).notNull().unique(),
    commissioningDate: date('commissioning_date'),
    currentMileageKm: integer('current_mileage_km').notNull().default(0),
    fitnessStatus: fitnessStatusEnum('fitness_status').default('FIT'),
    fitnessNotes: text('fitness_notes'),
    currentDepotId: uuid('current_depot_id').references(() => depots.id),
    homeDepotId: uuid('home_depot_id').references(() => depots.id),
    active: boolean('active').default(true),

    // Mileage balancing - target is calculated from fleet average
    targetMileageKm: integer('target_mileage_km'),
    // mileage_variance_km is calculated: current - target (done in queries)

    // Canvas display properties
    displayColor: varchar('display_color', { length: 7 }),
    displayOrder: integer('display_order'),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    index('idx_trains_fleet').on(table.fleetId),
    index('idx_trains_fitness').on(table.fitnessStatus),
    index('idx_trains_depot').on(table.currentDepotId),
  ]
);

/**
 * Routes - Operating lines/services
 *
 * A route represents a service that trains operate on.
 * Each route has expected daily mileage and train requirements.
 *
 * v2.1 additions:
 * - signaling_system, power_system: For compatibility matching
 * - tunnel_clearance_mm: Maximum vehicle width allowed
 * - allowed_fleet_ids: Which fleets can operate on this route
 */
export const routes = pgTable(
  'routes',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    routeCode: varchar('route_code', { length: 20 }).notNull().unique(),
    routeName: varchar('route_name', { length: 100 }).notNull(),
    lineId: varchar('line_id', { length: 20 }),
    expectedKmPerDay: integer('expected_km_per_day').notNull(),
    requiredTrains: integer('required_trains').notNull(),

    // v2.1: Route characteristics for compatibility matching
    defaultDailyKm: integer('default_daily_km'),
    signalingSystem: varchar('signaling_system', { length: 30 }), // 'ATC', 'CBTC', 'ERTMS', 'LEGACY'
    powerSystem: varchar('power_system', { length: 30 }), // 'THIRD_RAIL_750V', 'OVERHEAD_25KV', etc.
    tunnelClearanceMm: integer('tunnel_clearance_mm'),
    platformLengthM: decimal('platform_length_m', { precision: 5, scale: 2 }),
    maxAxleLoadTonnes: decimal('max_axle_load_tonnes', { precision: 4, scale: 2 }),

    // Restrictions - stored as array of UUID strings
    allowedFleetIds: text('allowed_fleet_ids').array(),
    requiresAto: boolean('requires_ato').default(false),
    minCars: integer('min_cars'),
    maxCars: integer('max_cars'),

    active: boolean('active').default(true),
    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [uniqueIndex('idx_routes_code').on(table.routeCode)]
);

/**
 * Tracks - Maintenance bays
 *
 * Physical maintenance positions within a depot.
 * Each track has a type that determines what maintenance can be performed.
 * Track capabilities (pit, crane, etc.) are stored in a separate table.
 */
export const tracks = pgTable(
  'tracks',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    depotId: uuid('depot_id')
      .notNull()
      .references(() => depots.id),
    trackNumber: varchar('track_number', { length: 20 }).notNull(),
    trackType: trackTypeEnum('track_type').notNull(),
    maxTrainLengthM: decimal('max_train_length_m', { precision: 5, scale: 2 }),
    hasOverheadCrane: boolean('has_overhead_crane').default(false),
    hasPitAccess: boolean('has_pit_access').default(false),

    active: boolean('active').default(true),
    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    uniqueIndex('idx_tracks_depot_number').on(table.depotId, table.trackNumber),
    index('idx_tracks_depot_type').on(table.depotId, table.trackType),
  ]
);

// ============================================================================
// Relations
// ============================================================================

export const depotsRelations = relations(depots, ({ many }) => ({
  fleets: many(fleets),
  trainsCurrentlyAt: many(trains, { relationName: 'currentDepot' }),
  trainsHomeAt: many(trains, { relationName: 'homeDepot' }),
  tracks: many(tracks),
}));

export const fleetsRelations = relations(fleets, ({ one, many }) => ({
  baseDepot: one(depots, {
    fields: [fleets.baseDepotId],
    references: [depots.id],
  }),
  trains: many(trains),
}));

export const trainsRelations = relations(trains, ({ one }) => ({
  fleet: one(fleets, {
    fields: [trains.fleetId],
    references: [fleets.id],
  }),
  currentDepot: one(depots, {
    fields: [trains.currentDepotId],
    references: [depots.id],
    relationName: 'currentDepot',
  }),
  homeDepot: one(depots, {
    fields: [trains.homeDepotId],
    references: [depots.id],
    relationName: 'homeDepot',
  }),
}));

export const tracksRelations = relations(tracks, ({ one }) => ({
  depot: one(depots, {
    fields: [tracks.depotId],
    references: [depots.id],
  }),
}));

/**
 * MMS Baseline & Drift Tables
 *
 * Plan stability through immutable baseline snapshots and drift monitoring.
 *
 * Baseline/Drift Architecture:
 * - Baselines are published snapshots of the PM schedule and mileage projections
 * - Drift analysis compares current state to baseline
 * - When drift exceeds thresholds, requires_replan flag is set
 *
 * Drift thresholds:
 * - Mileage: ±5.0%
 * - Schedule: ±14 days
 * - Fleet: ≥5 trains requiring replan
 *
 * @see specs/003-database-schema.md Section 3.8
 */

import { relations } from 'drizzle-orm';
import {
  boolean,
  date,
  decimal,
  index,
  integer,
  pgTable,
  text,
  timestamp,
  uniqueIndex,
  uuid,
  varchar,
} from 'drizzle-orm/pg-core';
import { depots, trains } from './core-fleet';
import { baselineStatusEnum } from './enums';
import { pmTypes } from './pm-management';
import { users } from './users';

/**
 * Plan Baselines - Immutable schedule snapshots
 *
 * A baseline captures the state of PM scheduling and mileage projections
 * at a point in time. Published baselines become the reference for drift analysis.
 *
 * Status lifecycle:
 * DRAFT -> PUBLISHED -> SUPERSEDED (when new baseline published)
 */
export const planBaselines = pgTable(
  'plan_baselines',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    name: varchar('name', { length: 100 }).notNull(),
    description: text('description'),
    version: varchar('version', { length: 20 }).notNull(), // 'v3.2'

    baselineDate: date('baseline_date').notNull(), // "As of" date
    horizonEnd: date('horizon_end').notNull(), // How far into future

    // Workflow
    status: baselineStatusEnum('status').default('DRAFT'),
    createdBy: uuid('created_by')
      .notNull()
      .references(() => users.id),
    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),

    publishedBy: uuid('published_by').references(() => users.id),
    publishedAt: timestamp('published_at', { withTimezone: true }),

    supersededBy: uuid('superseded_by'),
    supersededAt: timestamp('superseded_at', { withTimezone: true }),

    // Metrics at baseline time
    fleetCount: integer('fleet_count'),
    totalPmScheduled: integer('total_pm_scheduled'),
    totalManhourProjected: decimal('total_manhour_projected', { precision: 12, scale: 2 }),
  },
  (table) => [
    index('idx_baselines_status').on(table.status),
    index('idx_baselines_date').on(table.baselineDate),
  ]
);

/**
 * Baseline PM Schedule - Snapshot of scheduled maintenance
 *
 * Immutable copy of PM schedule at baseline time.
 * Used for drift comparison.
 */
export const baselinePmSchedule = pgTable(
  'baseline_pm_schedule',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    baselineId: uuid('baseline_id')
      .notNull()
      .references(() => planBaselines.id, { onDelete: 'cascade' }),

    trainId: uuid('train_id')
      .notNull()
      .references(() => trains.id),
    pmTypeId: uuid('pm_type_id')
      .notNull()
      .references(() => pmTypes.id),
    projectedDate: date('projected_date').notNull(),
    projectedMileageKm: integer('projected_mileage_km'),

    assignedDepotId: uuid('assigned_depot_id').references(() => depots.id),
    assignedHours: decimal('assigned_hours', { precision: 6, scale: 2 }),
  },
  (table) => [
    uniqueIndex('idx_baseline_pm_unique').on(
      table.baselineId,
      table.trainId,
      table.pmTypeId,
      table.projectedDate
    ),
    index('idx_baseline_pm_baseline').on(table.baselineId),
    index('idx_baseline_pm_train').on(table.trainId, table.projectedDate),
  ]
);

/**
 * Baseline Mileage Projection - Snapshot of mileage forecasts
 *
 * Immutable copy of mileage projections at baseline time.
 * Used for drift comparison.
 */
export const baselineMileageProjection = pgTable(
  'baseline_mileage_projection',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    baselineId: uuid('baseline_id')
      .notNull()
      .references(() => planBaselines.id, { onDelete: 'cascade' }),

    trainId: uuid('train_id')
      .notNull()
      .references(() => trains.id),
    projectionDate: date('projection_date').notNull(),
    projectedCumulativeKm: integer('projected_cumulative_km').notNull(),
    dailyRateKm: integer('daily_rate_km'), // Assumed daily accrual rate
  },
  (table) => [
    uniqueIndex('idx_baseline_mileage_unique').on(
      table.baselineId,
      table.trainId,
      table.projectionDate
    ),
    index('idx_baseline_mileage').on(table.baselineId, table.trainId),
  ]
);

/**
 * Drift Analysis - Comparison results
 *
 * Generated by drift monitor (nightly job).
 * Compares current state to baseline and flags trains requiring replan.
 */
export const driftAnalysis = pgTable(
  'drift_analysis',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    baselineId: uuid('baseline_id')
      .notNull()
      .references(() => planBaselines.id),
    analysisDate: date('analysis_date').notNull(),

    trainId: uuid('train_id')
      .notNull()
      .references(() => trains.id),

    // Mileage drift
    baselineProjectedKm: integer('baseline_projected_km').notNull(),
    actualKm: integer('actual_km').notNull(),
    // mileage_drift_km = actual - baseline (calculated in queries)
    mileageDriftPct: decimal('mileage_drift_pct', { precision: 5, scale: 2 }),

    // Schedule drift (days)
    avgPmDriftDays: decimal('avg_pm_drift_days', { precision: 5, scale: 1 }),
    maxPmDriftDays: integer('max_pm_drift_days'),

    // Threshold breach
    requiresReplan: boolean('requires_replan').default(false),
    replanReason: text('replan_reason'),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    uniqueIndex('idx_drift_unique').on(table.baselineId, table.trainId, table.analysisDate),
    index('idx_drift_baseline').on(table.baselineId, table.analysisDate),
    index('idx_drift_replan').on(table.requiresReplan, table.analysisDate),
  ]
);

// ============================================================================
// Relations
// ============================================================================

export const planBaselinesRelations = relations(planBaselines, ({ one, many }) => ({
  createdByUser: one(users, {
    fields: [planBaselines.createdBy],
    references: [users.id],
    relationName: 'createdBy',
  }),
  publishedByUser: one(users, {
    fields: [planBaselines.publishedBy],
    references: [users.id],
    relationName: 'publishedBy',
  }),
  supersededByBaseline: one(planBaselines, {
    fields: [planBaselines.supersededBy],
    references: [planBaselines.id],
    relationName: 'supersedes',
  }),
  pmScheduleSnapshots: many(baselinePmSchedule),
  mileageProjections: many(baselineMileageProjection),
  driftAnalyses: many(driftAnalysis),
}));

export const baselinePmScheduleRelations = relations(baselinePmSchedule, ({ one }) => ({
  baseline: one(planBaselines, {
    fields: [baselinePmSchedule.baselineId],
    references: [planBaselines.id],
  }),
  train: one(trains, {
    fields: [baselinePmSchedule.trainId],
    references: [trains.id],
  }),
  pmType: one(pmTypes, {
    fields: [baselinePmSchedule.pmTypeId],
    references: [pmTypes.id],
  }),
  assignedDepot: one(depots, {
    fields: [baselinePmSchedule.assignedDepotId],
    references: [depots.id],
  }),
}));

export const baselineMileageProjectionRelations = relations(
  baselineMileageProjection,
  ({ one }) => ({
    baseline: one(planBaselines, {
      fields: [baselineMileageProjection.baselineId],
      references: [planBaselines.id],
    }),
    train: one(trains, {
      fields: [baselineMileageProjection.trainId],
      references: [trains.id],
    }),
  })
);

export const driftAnalysisRelations = relations(driftAnalysis, ({ one }) => ({
  baseline: one(planBaselines, {
    fields: [driftAnalysis.baselineId],
    references: [planBaselines.id],
  }),
  train: one(trains, {
    fields: [driftAnalysis.trainId],
    references: [trains.id],
  }),
}));

/**
 * MMS Costing Tables
 *
 * Financial tracking for maintenance operations.
 * Used for TCO (Total Cost of Ownership) projections over the 12-year contract.
 *
 * Cost components:
 * - Labor: Hourly rates with shift/weekend/holiday multipliers
 * - Materials: Part costs with effective dating
 * - Overhead: 18% of direct costs (standard industry rate)
 *
 * TCO projection parameters:
 * - Inflation: 3% annually
 * - Discount rate: 5% for NPV calculations
 *
 * @see specs/003-database-schema.md Section 3.10
 */

import { relations } from 'drizzle-orm';
import {
  date,
  decimal,
  index,
  integer,
  pgTable,
  timestamp,
  uniqueIndex,
  uuid,
  varchar,
} from 'drizzle-orm/pg-core';
import { depots } from './core-fleet';

/**
 * Labor Rates - Hourly costs for maintenance work
 *
 * Rates can be depot-specific or global (depot_id = NULL).
 * Includes multipliers for overtime, weekend, and holiday work.
 */
export const laborRates = pgTable(
  'labor_rates',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    depotId: uuid('depot_id').references(() => depots.id), // NULL = global default
    effectiveFrom: date('effective_from').notNull(),
    effectiveTo: date('effective_to'),

    // Rate types
    regularHourlyRate: decimal('regular_hourly_rate', { precision: 10, scale: 2 }).notNull(),
    overtimeMultiplier: decimal('overtime_multiplier', { precision: 3, scale: 2 }).default('1.5'),
    weekendMultiplier: decimal('weekend_multiplier', { precision: 3, scale: 2 }).default('2.0'),
    holidayMultiplier: decimal('holiday_multiplier', { precision: 3, scale: 2 }).default('2.5'),

    // Shop rate (fully loaded with overhead, benefits, etc.)
    shopRateHourly: decimal('shop_rate_hourly', { precision: 10, scale: 2 }),

    currency: varchar('currency', { length: 3 }).default('SGD'),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    uniqueIndex('idx_labor_rates_depot_date').on(table.depotId, table.effectiveFrom),
    index('idx_labor_rates_depot').on(table.depotId),
  ]
);

/**
 * Material Costs - Part pricing history
 *
 * Historical part prices for accurate cost calculation.
 * Effective dating allows for price changes over time.
 */
export const materialCosts = pgTable(
  'material_costs',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    partNumber: varchar('part_number', { length: 50 }).notNull(),
    effectiveFrom: date('effective_from').notNull(),
    effectiveTo: date('effective_to'),

    unitCost: decimal('unit_cost', { precision: 12, scale: 2 }).notNull(),
    currency: varchar('currency', { length: 3 }).default('SGD'),
    supplier: varchar('supplier', { length: 100 }),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    uniqueIndex('idx_material_costs_part_date').on(table.partNumber, table.effectiveFrom),
    index('idx_material_costs_part').on(table.partNumber),
  ]
);

/**
 * Cost Baselines - Budget vs. Actual tracking
 *
 * Annual cost tracking for variance analysis.
 * Used for financial reporting and forecasting.
 */
export const costBaselines = pgTable(
  'cost_baselines',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    fiscalYear: integer('fiscal_year').notNull(),
    depotId: uuid('depot_id').references(() => depots.id),

    // Budget
    budgetLaborHours: decimal('budget_labor_hours', { precision: 12, scale: 2 }),
    budgetLaborCost: decimal('budget_labor_cost', { precision: 14, scale: 2 }),
    budgetMaterialCost: decimal('budget_material_cost', { precision: 14, scale: 2 }),
    budgetTotal: decimal('budget_total', { precision: 14, scale: 2 }),

    // Actuals (updated monthly)
    actualLaborHours: decimal('actual_labor_hours', { precision: 12, scale: 2 }),
    actualLaborCost: decimal('actual_labor_cost', { precision: 14, scale: 2 }),
    actualMaterialCost: decimal('actual_material_cost', { precision: 14, scale: 2 }),
    actualTotal: decimal('actual_total', { precision: 14, scale: 2 }),

    // variance_pct calculated in queries: ((actual - budget) / budget) * 100

    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    uniqueIndex('idx_cost_baselines_year_depot').on(table.fiscalYear, table.depotId),
    index('idx_cost_baselines_year').on(table.fiscalYear),
  ]
);

// ============================================================================
// Relations
// ============================================================================

export const laborRatesRelations = relations(laborRates, ({ one }) => ({
  depot: one(depots, {
    fields: [laborRates.depotId],
    references: [depots.id],
  }),
}));

export const costBaselinesRelations = relations(costBaselines, ({ one }) => ({
  depot: one(depots, {
    fields: [costBaselines.depotId],
    references: [depots.id],
  }),
}));

