   930→  /**
   931→   * Check if PM is locked by Maximo (INPRG work order).
   932→   */
   933→  async checkMaximoLock(pmScheduleId: string): Promise<{
   934→    isLocked: boolean;
   935→    workOrderId: string | null;
   936→    maximoStatus: string | null;
   937→    reason: string | null;
   938→  }> {
   939→    return this.traced('checkMaximoLock', async (span) => {
   940→      span.setAttribute('pm.scheduleId', pmScheduleId);
   941→
   942→      const pm = await this.db.query.pmSchedule.findFirst({
   943→        where: eq(pmSchedule.id, pmScheduleId),
