/**
 * MMS PM Scheduler Service - Tactical PM Scheduling
 *
 * Schedules preventive maintenance within a 12-week horizon, respecting:
 * - Compliance windows (mileage OR time triggers)
 * - PM hierarchy (C4 satisfies C1/C2/C3)
 * - Track capability requirements
 * - Material constraints (hard 14 days, soft 90 days)
 * - Labor capacity (depot man-hour availability)
 * - Maximo lock status (INPRG work orders are read-only)
 * - Service demand (fleet availability)
 *
 * Key business rules:
 * - Compliance window: ±10% of interval (mileage or months)
 * - PM hierarchy: Higher-level PMs satisfy lower-level requirements
 * - Material hard constraint: BLOCKING parts must be available within 14 days
 * - Material soft constraint: Warning if parts unavailable within 90 days
 * - Labor capacity: PM hours must fit within weekly depot capacity
 * - Track utilization target: 85%
 * - Maximo lock: Cannot modify PM with INPRG work order
 *
 * @see specs/003-database-schema.md Section 3.5 (PM Management)
 * @see specs/004-domain-services.md Section 4.4 (PM Scheduler)
 */

import { eq, and, sql, desc, inArray, gte, lte, isNull, count } from 'drizzle-orm';
import type { SQL } from 'drizzle-orm';
import { BaseService, MmsAttributes } from '../lib/services/base';
import {
  pmSchedule,
  pmTypes,
  pmMaterialRequirements,
  trains,
  tracks,
  trackCapabilities,
  pmCapabilityRequirements,
  inventoryPositions,
  materialReservations,
  pmScheduleHistory,
  mileageReadings,
  type PmScheduleRecord,
  type NewPmScheduleRecord,
  type PmType,
  type Train,
  type Track,
  type NewPmScheduleHistory,
} from '../lib/db/schema';
import {
  NotFoundError,
  PmScheduleNotFoundError,
  TrainNotFoundError,
  MaximoLockError,
  ComplianceWindowError,
  TrackConflictError,
  MaterialConstraintError,
  ServiceDemandViolationError,
  LaborCapacityError,
  ValidationError,
  BusinessRuleError,
} from '../lib/errors';
import { getServiceDemandService } from './service-demand';
import { getUnavailabilityService } from './unavailability';
import { getManHourLevelingService, type LaborCapacityResult } from './man-hour-leveling';

// =============================================================================
// Types
// =============================================================================

/** Track type values */
type TrackType = 'LIGHT' | 'HEAVY' | 'OVERHAUL' | 'STABLING';

/** Material criticality values */
type MaterialCriticality = 'BLOCKING' | 'DEFERRABLE' | 'CONSUMABLE';

/** Reservation type values */
type ReservationType = 'SOFT' | 'HARD';

/** PM due calculation result */
export interface PmDueResult {
  pmTypeId: string;
  pmCode: string;
  pmName: string;
  trainId: string;
  trainNumber: string;
  fleetId: string;
  dueMileageKm: number | null;
  dueDate: string | null;
  currentMileageKm: number;
  kmUntilDue: number | null;
  daysUntilDue: number | null;
  triggerType: 'MILEAGE' | 'TIME' | 'BOTH';
  complianceWindow: ComplianceWindow;
  isOverdue: boolean;
  lastPmDate: string | null;
  lastPmMileageKm: number | null;
}

/** Compliance window for scheduling */
export interface ComplianceWindow {
  startDate: string;
  endDate: string;
  startMileageKm: number | null;
  endMileageKm: number | null;
  idealDate: string;
  idealMileageKm: number | null;
}

/** Material availability check result */
export interface MaterialAvailability {
  partNumber: string;
  partDescription: string | null;
  criticality: MaterialCriticality;
  requiredQuantity: number;
  availableQuantity: number;
  depotId: string;
  isAvailable: boolean;
  shortfall: number;
  leadTimeDays: number;
  expectedAvailableDate: string | null;
}

/** Material constraint check result */
export interface MaterialConstraintResult {
  isBlocked: boolean;
  hardConstraintViolations: MaterialAvailability[];
  softConstraintWarnings: MaterialAvailability[];
  totalMissingParts: number;
  reservations: Array<{
    partNumber: string;
    quantity: number;
    type: ReservationType;
  }>;
}

/** Track allocation result */
export interface TrackAllocation {
  trackId: string;
  trackNumber: string;
  depotId: string;
  depotCode: string;
  trackType: TrackType;
  startDate: string;
  endDate: string;
  hasAllCapabilities: boolean;
  missingCapabilities: string[];
}

/** Scheduling result for a single PM */
export interface SchedulingResultItem {
  trainId: string;
  trainNumber: string;
  pmTypeId: string;
  pmCode: string;
  status: 'SCHEDULED' | 'DEFERRED' | 'BLOCKED';
  targetDate: string | null;
  targetMileageKm: number | null;
  trackAllocation: TrackAllocation | null;
  materialConstraint: MaterialConstraintResult | null;
  laborCapacity: LaborCapacityResult | null;
  complianceWindow: ComplianceWindow;
  deferralReason: string | null;
  warnings: string[];
  explanation: SchedulingExplanation;
}

/** Explanation trace for scheduling decisions */
export interface SchedulingExplanation {
  mileageTrigger: {
    intervalKm: number | null;
    currentMileageKm: number;
    lastPmMileageKm: number | null;
    kmSinceLastPm: number | null;
    kmUntilDue: number | null;
  };
  timeTrigger: {
    intervalMonths: number | null;
    lastPmDate: string | null;
    daysSinceLastPm: number | null;
    daysUntilDue: number | null;
  };
  hierarchySatisfied: {
    satisfiedBy: string | null;
    satisfiedOnDate: string | null;
    counterResetFrom: number | null;
  };
  trackSelection: {
    candidateTracks: number;
    selectedTrackId: string | null;
    selectionReason: string;
  };
  materialCheck: {
    totalParts: number;
    availableParts: number;
    blockedParts: number;
    warningParts: number;
  };
  laborCapacityCheck: {
    estimatedHours: number;
    weeklyCapacity: number;
    currentUtilization: number;
    utilizationAfterScheduling: number;
    hasCapacity: boolean;
  };
  constraints: string[];
}

/** Full scheduling result */
export interface SchedulingResult {
  horizonStart: string;
  horizonEnd: string;
  scheduled: SchedulingResultItem[];
  deferred: SchedulingResultItem[];
  blocked: SchedulingResultItem[];
  materialWarnings: Array<{
    trainId: string;
    trainNumber: string;
    pmCode: string;
    targetDate: string;
    warnings: MaterialAvailability[];
  }>;
  summary: {
    totalProcessed: number;
    totalScheduled: number;
    totalDeferred: number;
    totalBlocked: number;
    trackUtilizationPct: number;
  };
}

/** Request to schedule a PM */
export interface SchedulePmRequest {
  trainId: string;
  pmTypeId: string;
  targetDate: string;
  assignedDepotId?: string;
  assignedTrackId?: string;
  assignedShift?: 'DAY' | 'NIGHT' | 'WEEKEND' | 'HOLIDAY';
  notes?: string;
  createdBy?: string;
  skipMaterialCheck?: boolean;
  skipServiceDemandCheck?: boolean;
  skipLaborCapacityCheck?: boolean;
}

/** Request to move a PM */
export interface MovePmRequest {
  pmScheduleId: string;
  newTargetDate: string;
  newTrackId?: string;
  reason: string;
  movedBy: string;
}

/** Request to run tactical scheduling */
export interface TacticalScheduleRequest {
  fleetId?: string;
  depotId?: string;
  horizonWeeks?: number;
  dryRun?: boolean;
  respectLocks?: boolean;
}

/** PM with details for scheduling */
interface PmWithDetails extends PmScheduleRecord {
  train: Train | null;
  pmType: PmType | null;
  assignedTrack: Track | null;
}

// =============================================================================
// Constants
// =============================================================================

/** Default horizon for tactical scheduling (weeks) */
const DEFAULT_HORIZON_WEEKS = 12;

/** Hard material constraint window (days before PM) */
const HARD_MATERIAL_WINDOW_DAYS = 14;

/** Soft material constraint window (days before PM) */
const SOFT_MATERIAL_WINDOW_DAYS = 90;

/** Default daily mileage rate for projections (km) */
const DEFAULT_DAILY_KM = 250;

/** Default compliance tolerance percentage */
const DEFAULT_TOLERANCE_PCT = 10;

// =============================================================================
// PM Scheduler Service
// =============================================================================

export class PMSchedulerService extends BaseService {
  private serviceDemandService = getServiceDemandService();
  private unavailabilityService = getUnavailabilityService();
  private manHourLevelingService = getManHourLevelingService();

  constructor() {
    super({ name: 'pm-scheduler-service', version: '1.0.0' });
  }

  // ===========================================================================
  // Compliance Window Calculation
  // ===========================================================================

  /**
   * Calculate compliance window for a PM type and train.
   *
   * The compliance window defines the valid date range for scheduling a PM.
   * It is calculated based on:
   * - Mileage trigger: intervalKm ± tolerance%
   * - Time trigger: intervalMonths ± tolerance%
   * - Whichever comes first determines the due date
   *
   * @param trainId - Train to calculate for
   * @param pmTypeId - PM type to calculate for
   * @returns Compliance window with start/end dates and mileage
   */
  async calculateComplianceWindow(
    trainId: string,
    pmTypeId: string
  ): Promise<PmDueResult> {
    return this.traced('calculateComplianceWindow', async (span) => {
      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
      span.setAttribute('pm.typeId', pmTypeId);

      // Get train details
      const train = await this.db.query.trains.findFirst({
        where: eq(trains.id, trainId),
        with: { fleet: true },
      });

      if (!train) {
        throw new TrainNotFoundError(trainId);
      }

      span.setAttribute(MmsAttributes.TRAIN_NUMBER, train.trainNumber);
      span.setAttribute(MmsAttributes.FLEET_ID, train.fleetId);

      // Get PM type details
      const pmType = await this.db.query.pmTypes.findFirst({
        where: and(
          eq(pmTypes.id, pmTypeId),
          eq(pmTypes.active, true)
        ),
      });

      if (!pmType) {
        throw new NotFoundError(`PM type not found: ${pmTypeId}`, {
          entityType: 'pm_type',
          entityId: pmTypeId,
        });
      }

      // Get last completed PM of this type for this train
      const lastPm = await this.getLastCompletedPm(trainId, pmTypeId);

      // Check if a higher-level PM has satisfied this requirement
      const hierarchySatisfied = await this.checkHierarchySatisfaction(
        trainId,
        pmType,
        lastPm?.completedAt ?? null
      );

      // Use hierarchy satisfaction if more recent
      const effectiveLastPm = hierarchySatisfied?.satisfiedByPm &&
        (!lastPm || new Date(hierarchySatisfied.satisfiedByPm.completedAt ?? 0) > new Date(lastPm.completedAt ?? 0))
        ? hierarchySatisfied.satisfiedByPm
        : lastPm;

      const lastPmDate = effectiveLastPm?.completedAt
        ? new Date(effectiveLastPm.completedAt).toISOString().split('T')[0]
        : train.commissioningDate ?? null;
      const lastPmMileageKm = effectiveLastPm?.completedMileageKm ?? 0;

      // Calculate due date and mileage
      const currentMileageKm = train.currentMileageKm ?? 0;
      const today = new Date();
      const todayStr = today.toISOString().split('T')[0];

      // Get early/late tolerance
      const earlyTolerancePct = Number(pmType.earlyTolerancePct) || DEFAULT_TOLERANCE_PCT;
      const lateTolerancePct = Number(pmType.lateTolerancePct) || DEFAULT_TOLERANCE_PCT;

      // Calculate mileage trigger
      let dueMileageKm: number | null = null;
      let kmUntilDue: number | null = null;
      let mileageWindowStart: number | null = null;
      let mileageWindowEnd: number | null = null;

      if (pmType.intervalKm) {
        dueMileageKm = lastPmMileageKm + pmType.intervalKm;
        kmUntilDue = dueMileageKm - currentMileageKm;

        const toleranceKm = pmType.intervalKm * (earlyTolerancePct / 100);
        mileageWindowStart = dueMileageKm - toleranceKm;
        mileageWindowEnd = dueMileageKm + (pmType.intervalKm * (lateTolerancePct / 100));
      }

      // Calculate time trigger
      let dueDate: string | null = null;
      let daysUntilDue: number | null = null;
      let dateWindowStart: string | null = null;
      let dateWindowEnd: string | null = null;

      if (pmType.intervalMonths && lastPmDate) {
        const lastDate = new Date(lastPmDate);
        const dueDateTime = new Date(lastDate);
        dueDateTime.setMonth(dueDateTime.getMonth() + pmType.intervalMonths);
        dueDate = dueDateTime.toISOString().split('T')[0];
        daysUntilDue = Math.ceil((dueDateTime.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));

        const toleranceDays = Math.round((pmType.intervalMonths * 30) * (earlyTolerancePct / 100));
        const lateDays = Math.round((pmType.intervalMonths * 30) * (lateTolerancePct / 100));

        const windowStartDate = new Date(dueDateTime);
        windowStartDate.setDate(windowStartDate.getDate() - toleranceDays);
        dateWindowStart = windowStartDate.toISOString().split('T')[0];

        const windowEndDate = new Date(dueDateTime);
        windowEndDate.setDate(windowEndDate.getDate() + lateDays);
        dateWindowEnd = windowEndDate.toISOString().split('T')[0];
      }

      // Determine trigger type (which comes first)
      let triggerType: 'MILEAGE' | 'TIME' | 'BOTH' = 'BOTH';
      let idealDate = todayStr;
      let idealMileageKm = currentMileageKm;

      if (dueMileageKm !== null && dueDate !== null) {
        // Convert mileage due to date using daily rate
        const dailyKm = await this.getAverageDailyKm(trainId);
        const mileageDueDateMs = today.getTime() + ((kmUntilDue ?? 0) / dailyKm) * 24 * 60 * 60 * 1000;
        const mileageDueDate = new Date(mileageDueDateMs);

        const timeDueDate = new Date(dueDate);

        if (mileageDueDate < timeDueDate) {
          triggerType = 'MILEAGE';
          idealDate = mileageDueDate.toISOString().split('T')[0];
          idealMileageKm = dueMileageKm;
        } else if (timeDueDate < mileageDueDate) {
          triggerType = 'TIME';
          idealDate = dueDate;
          // Estimate mileage at time due date
          const daysToTimeDue = Math.ceil((timeDueDate.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
          idealMileageKm = currentMileageKm + (daysToTimeDue * dailyKm);
        } else {
          triggerType = 'BOTH';
          idealDate = dueDate;
          idealMileageKm = dueMileageKm;
        }
      } else if (dueMileageKm !== null) {
        triggerType = 'MILEAGE';
        const dailyKm = await this.getAverageDailyKm(trainId);
        const mileageDueDateMs = today.getTime() + ((kmUntilDue ?? 0) / dailyKm) * 24 * 60 * 60 * 1000;
        idealDate = new Date(mileageDueDateMs).toISOString().split('T')[0];
        idealMileageKm = dueMileageKm;
      } else if (dueDate !== null) {
        triggerType = 'TIME';
        idealDate = dueDate;
        const dailyKm = await this.getAverageDailyKm(trainId);
        const daysToTimeDue = Math.ceil((new Date(dueDate).getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
        idealMileageKm = currentMileageKm + (daysToTimeDue * dailyKm);
      }

      // Calculate compliance window dates
      const dailyKm = await this.getAverageDailyKm(trainId);
      let complianceStartDate = dateWindowStart ?? todayStr;
      let complianceEndDate = dateWindowEnd ?? todayStr;

      if (mileageWindowStart !== null) {
        const kmToStart = mileageWindowStart - currentMileageKm;
        const daysToStart = Math.max(0, Math.ceil(kmToStart / dailyKm));
        const startDateFromMileage = new Date(today);
        startDateFromMileage.setDate(startDateFromMileage.getDate() + daysToStart);

        if (!dateWindowStart || startDateFromMileage < new Date(dateWindowStart)) {
          complianceStartDate = startDateFromMileage.toISOString().split('T')[0];
        }
      }

      if (mileageWindowEnd !== null) {
        const kmToEnd = mileageWindowEnd - currentMileageKm;
        const daysToEnd = Math.ceil(kmToEnd / dailyKm);
        const endDateFromMileage = new Date(today);
        endDateFromMileage.setDate(endDateFromMileage.getDate() + daysToEnd);

        if (!dateWindowEnd || endDateFromMileage < new Date(dateWindowEnd)) {
          complianceEndDate = endDateFromMileage.toISOString().split('T')[0];
        }
      }

      // Ensure start date is not in the past
      if (complianceStartDate < todayStr) {
        complianceStartDate = todayStr;
      }

      // Check if overdue
      const isOverdue = complianceEndDate < todayStr;

      const result: PmDueResult = {
        pmTypeId,
        pmCode: pmType.pmCode,
        pmName: pmType.pmName,
        trainId,
        trainNumber: train.trainNumber,
        fleetId: train.fleetId,
        dueMileageKm,
        dueDate,
        currentMileageKm,
        kmUntilDue,
        daysUntilDue,
        triggerType,
        complianceWindow: {
          startDate: complianceStartDate,
          endDate: complianceEndDate,
          startMileageKm: mileageWindowStart,
          endMileageKm: mileageWindowEnd,
          idealDate,
          idealMileageKm,
        },
        isOverdue,
        lastPmDate,
        lastPmMileageKm,
      };

      span.setAttribute('pm.triggerType', triggerType);
      span.setAttribute('pm.isOverdue', isOverdue);
      span.setAttribute('pm.kmUntilDue', kmUntilDue ?? -1);

      return result;
    });
  }

  /**
   * Calculate PM due dates for all PM types for a train.
   */
  async calculateAllPmDue(trainId: string): Promise<PmDueResult[]> {
    return this.traced('calculateAllPmDue', async (span) => {
      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);

      // Get train with fleet
      const train = await this.db.query.trains.findFirst({
        where: eq(trains.id, trainId),
      });

      if (!train) {
        throw new TrainNotFoundError(trainId);
      }

      // Get all active PM types for this fleet
      const pmTypesList = await this.db.query.pmTypes.findMany({
        where: and(
          eq(pmTypes.fleetId, train.fleetId),
          eq(pmTypes.active, true)
        ),
        orderBy: [desc(pmTypes.intervalKm)],
      });

      const results: PmDueResult[] = [];

      for (const pmType of pmTypesList) {
        const dueResult = await this.calculateComplianceWindow(trainId, pmType.id);
        results.push(dueResult);
      }

      // Sort by due date (most urgent first)
      results.sort((a, b) => {
        const aDate = a.complianceWindow.idealDate;
        const bDate = b.complianceWindow.idealDate;
        return aDate.localeCompare(bDate);
      });

      span.setAttribute('result.pmCount', results.length);
      span.setAttribute('result.overdueCount', results.filter(r => r.isOverdue).length);

      return results;
    });
  }

