          });
        }
      }

      const [result] = await tx.insert(trainComponents).values(data).returning();
      span.setAttribute('component.id', result.id);

      this.log.info(
        { componentId: result.id, serialNumber: data.serialNumber, type: data.componentType },
        'Component created'
